mapper.select:
SELECT COUNT(DISTINCT session_id)
FROM match_record


        AND user_id = #{userId}


        AND match_mode = #{matchMode}

    AND session_id IS NOT NULL

SELECT session_id AS sessionId, match_mode AS matchMode, CASE WHEN match_mode = 'TEXT' THEN query_text WHEN match_mode = 'PATENT' THEN source_patent_title ELSE query_text END AS querySource, source_patent_id AS sourcePatentId, top_k AS topK, COUNT(*) AS matchCount, MIN(created_at) AS createdAt FROM match_record
AND user_id = #{userId}
AND match_mode = #{matchMode}
AND session_id IS NOT NULL
GROUP BY session_id, match_mode, query_text, source_patent_title, source_patent_id, top_k ORDER BY createdAt DESC LIMIT #{limit} OFFSET #{offset}

SELECT
    target_patent_id      AS targetPatentId,
    target_patent_title   AS targetPatentTitle,
    similarity_score      AS similarityScore
FROM match_record
WHERE session_id = #{sessionId}

    AND user_id = #{userId}

ORDER BY similarity_score DESC
LIMIT #{limit}

SELECT *
FROM match_record
WHERE session_id = #{sessionId}

    AND user_id = #{userId}

ORDER BY similarity_score DESC
